execute(workflowId: string, params: Record<string, unknown>): string {
    const executionId = `exec-${++this.eventCounter}-${Date.now()}`;
    const prompt = this.buildPrompt(workflowId, params);
    const tool = (params.tool as string) ?? 'claude';

    const childProcess = this.spawnFn('maestro', [
      'delegate', prompt, '--to', tool, '--mode', 'write',
    ]);

    const callbacks = new Set<(event: DelegateEvent) => void>();
    this.activeProcesses.set(executionId, {
      process: childProcess, executionId, callbacks,
    });

    childProcess.stdout?.on('data', (chunk: Buffer | string) => {
      const text = typeof chunk === 'string' ? chunk : chunk.toString();
      for (const line of text.split('\n')) {
        const event = this.parseLine(line);
        if (event) { this.emitEvent(event); }
      }
    });

    childProcess.stderr?.on('data', (chunk: Buffer | string) => {
      const text = typeof chunk === 'string' ? chunk : chunk.toString();
      console.error(`[DelegateExecutor:${executionId}] stderr:`, text);
    });

    childProcess.on('exit', (code) => {
      const entry = this.activeProcesses.get(executionId);
      if (entry) { this.activeProcesses.delete(executionId); }
      if (code !== null && code !== 0) {
        const failedEvent: DelegateEvent = {
          type: 'failed', executionId,
          output: `Process exited with code ${code}`,
          timestamp: new Date().toISOString(),
        };
        this.emitEvent(failedEvent);
      }
    });

    return executionId;
  }

private parseLine(line: string): DelegateEvent | null {
    const trimmed = line.trim();
    if (trimmed.length === 0) { return null; }
    try {
      const parsed = JSON.parse(trimmed);
      return {
        type: parsed.type, executionId: parsed.executionId,
        stepIndex: parsed.stepIndex, stepName: parsed.stepName,
        output: parsed.output, timestamp: parsed.timestamp,
      } satisfies DelegateEvent;
    } catch { return null; }
  }

private emitEvent(event: DelegateEvent): void {
    for (const cb of this.globalCallbacks) {
      try { cb(event); } catch (err) { console.error(...); }
    }
    const entry = this.activeProcesses.get(event.executionId);
    if (entry) {
      for (const cb of entry.callbacks) {
        try { cb(event); } catch (err) { console.error(...); }
      }
    }
    const workflowEvent = DELEGATE_TO_WORKFLOW_EVENT[event.type];
    if (workflowEvent) {
      this.eventBus.publish(
        workflowEvent, Channels.WORKFLOW, { ...event }, 'server',
      );
    }
  }

start(port: number): void {
    this.wss = new WebSocketServer({ port });
    this.wss.on('connection', (ws) => {
      const clientId = `client-${++this.clientCounter}`;
      const client: ClientConnection = {
        ws, id: clientId,
        subscribedChannels: new Set(),
        connectedAt: new Date().toISOString(),
        lastActivityAt: new Date().toISOString(),
      };
      this.clients.set(clientId, client);
      this.translator.setClientMode(clientId, 'simple');
      this.sendToClient(client, {
        channel: Channels.STATE, type: StateSyncEvents.RECONNECT,
        payload: { clientId, mode: 'simple' },
        timestamp: new Date().toISOString(),
      });
      ws.on('message', (data) => { ... });
      ws.on('close', () => { ... });
      ws.on('error', (err) => { ... });
    });
    this.eventBus.onAny((payload, event) => {
      this.broadcastEvent(event as InternalEvent);
    });
  }

private broadcastEvent(event: InternalEvent): void {
    for (const client of this.clients.values()) {
      const message: WSMessage = {
        channel: event.channel, type: event.type,
        payload: event.payload, timestamp: event.timestamp,
      };
      if (client.subscribedChannels.has(event.channel) || client.subscribedChannels.has('*')) {
        if (typeof event.payload === 'object' && event.payload !== null) {
          const { translated } = this.translator.translate(
            event.payload as Record<string, unknown>, client.id
          );
          message.payload = translated;
        }
        this.sendToClient(client, message);
      }
    }
  }

export const Channels = {
  WORKFLOW: 'workflow', PROJECT: 'project',
  DIALOG: 'dialog', TERMINAL: 'terminal',
  GATE: 'gate', STATE: 'state',
} as const;

export const DialogEvents = {
  SESSION_CREATED: 'dialog:session-created',
  STREAM_CHUNK: 'dialog:stream-chunk',
  INTENT_ROUTED: 'dialog:intent-routed',
  SESSION_CLOSED: 'dialog:session-closed',
} as const;

export const TerminalEvents = {
  OUTPUT: 'term:output', INPUT: 'term:input',
  RESIZE: 'term:resize', EXIT: 'term:exit',
  CREATED: 'term:created',
} as const;

wsClient.on(Channels.STATE, (message) => {
  if (message.type === 'state:sync') {
    const event = (message.payload as { event: { type: string; payload: Record<string, unknown> } }).event;
    if (event.type === 'project:state-update' || event.type === 'project:milestone-changed') {
      const state = event.payload as unknown as ProjectState;
      if (state.projectId) { projectState.set(state); }
    }
  }
});

wsClient.on(Channels.WORKFLOW, (message) => {
  if (message.type === 'workflow:step-update') {
    const event = (message.payload as unknown) as DelegateEvent;
    const { executionId, type, stepIndex, stepName, output, timestamp } = event;
    let execution = executionMap.get(executionId);
    if (!execution) {
      execution = { id: executionId, workflowId: '', params: {}, status: 'running', steps: [], startedAt: timestamp, completedAt: null };
    }
    // ... status mapping and step accumulation ...
    executionMap.set(executionId, execution);
    activeWorkflows.update((workflows) => { ... });
  }
});

