export class CLIAdapterRegistry {
  private adapters = new Map<string, CLIAdapter>();
  private execFn: ExecFn;

  constructor(execFn?: ExecFn) { this.execFn = execFn ?? exec; }

  register(version: string, adapter: CLIAdapter): void {
    this.adapters.set(version, adapter);
  }

  getAdapter(version: string): CLIAdapter {
    const adapter = this.adapters.get(version);
    if (!adapter) { throw new UnsupportedVersionError(version); }
    return adapter;
  }

  detectVersion(): Promise<string> {
    return new Promise((resolve, reject) => {
      this.execFn('maestro --version', (error, stdout) => {
        if (error) { reject(error); return; }
        const raw = stdout.trim();
        const match = raw.match(/^v?(\d+)/);
        if (!match) { reject(new Error(`Cannot parse version from output: "${raw}"`)); return; }
        resolve(match[1]);
      });
    });
  }
}

start(): void {
    this.eventBus.subscribe('workflow:step-update', (payload) => {
      this.emitInProcessEvent('workflow:step-update', payload as Record<string, unknown>);
    });
    this.eventBus.subscribe('workflow:execution-started', (payload) => { ... });
    this.eventBus.subscribe('workflow:execution-completed', (payload) => { ... });
    this.eventBus.subscribe('project:state-update', (payload) => { ... });

    if (this.watchPaths.length > 0) {
      this.watcher = chokidar.watch(this.watchPaths, {
        ignoreInitial: true, ignored: /(^|[/\\])\.\./, persistent: true,
      });
      this.watcher.on('all', (event: string, path: string) => {
        this.handleFilesystemEvent(event, path);
      });
    }
  }
